#include<bits/stdc++.h>
#define LL long long
using namespace std;
const int N = 1e5+5;
struct node{LL x,opt;}a[N];
LL n,s[2][N],ans;map<int,int> p;
bool cmp(node d1,node d2){return d1.x<d2.x;}
int main(){
    //freopen("fairphoto.in","r",stdin);
    //freopen("fairphoto.out","w",stdout);
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>a[i].x;char c;
        cin>>c;a[i].opt=(c=='S');
    }
    sort(a+1,a+n+1,cmp);
    if(n<=10000){
        for(int i=1;i<=n;i++)
            s[a[i].opt][i]=s[a[i].opt][i-1]+1,
            s[1-a[i].opt][i]=s[1-a[i].opt][i-1];
        for(int i=1;i<=n;i++)for(int j=i;j<=n;j++){
            int x=s[0][j]-s[0][i-1],y=s[1][j]-s[1][i-1];
            if(x>=y&&(x-y)%2==0)ans=max(ans,a[j].x-a[i].x);
        }
        cout<<ans<<"\n";
    }
    else{
        int now=0;
        for(int i=1;i<=n;i++){
            if(a[i].opt)now--;else now++;
            if(now>=0){
                if(now%2==0)ans=max(ans,a[i].x-a[1].x);
                else ans=max(ans,a[i].x-a[2].x);
            }
            else{
                if(!p[abs(now)])p[abs(now)]=i;
                else ans=max(ans,a[i].x-a[p[abs(now)]+1].x);
            }
        }
        cout<<ans<<"\n";
    }
    return 0;
}
